package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testWithEscape() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Given
        char escape = '\\';

        // When
        Method withEscapeMethod = CSVFormat.class.getDeclaredMethod("withEscape", Character.class);
        withEscapeMethod.setAccessible(true);
        CSVFormat result = (CSVFormat) withEscapeMethod.invoke(csvFormat, Character.valueOf(escape));

        // Then
        assertEquals(Character.valueOf(escape), result.getEscapeCharacter());
    }
}
